
(function () {
    var click_cnt = 0;
    jQuery(document).ready(function ($) {
        $("html").click(function (e) {
            var n = 18;
            var $i;
            click_cnt++;
            if (click_cnt == 10) {
                $i = $("<b></b>").text("ɛOωOɜ");
            }else if (click_cnt == 20) {
                $i = $("<b></b>").text("(๑•́ ∀ •̀๑)");
            }else {
                $i = $("<b></b>").text("❤");
            }
            n = Math.round(Math.random() * 50 + 150);
            var x = e.pageX,
                y = e.pageY - $(document).scrollTop();;
            $i.css({
                "z-index": 9999,
                "top": y - 20,
                "left": x,
                "position": "absolute",
                "color": "#E94F06",
                "font-size": n,
                "-moz-user-select": "none",
                "-webkit-user-select": "none",
                "-ms-user-select": "none"
            });
            $(".rt").append($i);
            $i.animate({
                "top": y - 180,
                "opacity": 0
            }, 1500, function () {
                $i.remove();
            });
        });
    });
})();


// ==UserScript==
// @name         鼠标移动点击出现随机颜色表情符号
// @version      1.2
// @description  242个符号随机出现，双击切换移动鼠标出现痕迹表情符号
// @author       日狗少年
// @include      /^https?\:\/\/[^\s]*/
// @grant        GM_addStyle
// @require      http://images.qijishow.com/jquery.min1.7.js
// @run-at       document_start
// @grant        unsafeWindow
// @namespace    
// ==/UserScript==
var index1 = 0;
var index2 = 0;
var lastx;
var lasty;
(function () {
    var flag = true;
    var chars = ['😀', '😁', '😂', '😃', '😄', '😅', '😆', '😇', '😈', '😉', '😊', '😋', '😌', '😍', '😎', '😏', '😐', '😑', '😒', '😓', '😔', '😕', '😖', '😗', '😘', '😙', '😚', '😛', '😜', '😝', '😞', '😟', '😠', '😡', '😢', '😣', '😤', '😥', '😦', '😧', '😨', '😩', '😪', '😫', '😬', '😭', '😮', '😯', '😰', '😱', '😲', '😳', '😴', '😵', '😶', '😷'];
    var gzkchars = ['❤', '❤', '❤', '❤', '❤'];
    
    jQuery(document).ready(function ($) {
        $("html").mousemove(function (e) {
            if (flag) {
                var x = e.pageX,
                    y = e.pageY - $(document).scrollTop();
                    var w=window.innerWidth
                    || document.documentElement.clientWidth
                    || document.body.clientWidth;
                    
                    var h=window.innerHeight
                    || document.documentElement.clientHeight
                    || document.body.clientHeight;
                    
                var n = Math.round(Math.random() * 50 + 50);
                
                if (0 && (Math.abs(x - lastx) < 0 && Math.abs(y - lasty) < 0 || x + n  > w  || y + n > h )) {
                    return;
                } else {
                    lastx = x;
                    lasty = y;
                }

                var color = "#" + ("00000" + ((Math.random() * 16777215 + 0.5) >> 0).toString(16)).slice(-6);
                var xr = Math.ceil(Math.random() * 800) - 400;
                var yr = Math.ceil(Math.random() * 800) - 400;
                var $i;
                if (index1 == gzkchars.length) {
                    $i = $("<b></b>").text(gzkchars[(index1++)]);
                    index1 = 0;
                }
                else
                    $i = $("<b></b>").text(gzkchars[(index1++)]);
                
               
                $i.css({
                    "z-index": -9999,
                    "color": color,
                    "top": y,
                    "left": x,
                    "position": "absolute",
                    "font-size": n,
                    "-moz-user-select": "none",
                    "-webkit-user-select": "none",
                    "-ms-user-select": "none"
                });
                $(".rt").append($i);
                $i.animate({
                    "top": y + yr,
                    "left": x + xr,
                    "opacity": 0,
                }, 1000, function () {
                    $i.remove();
                });
            }
        });
    });
})();